#include<bits/stdc++.h>
using namespace std;
char str[100010],str2[100010];
int main()
{
	int t;
	scanf("%d",&t);
	while(t--)
	{
		int n,k,cnt=0;
		scanf("%d%d%s",&n,&k,str+1);
		int g=-100010,h=-100010;
		for(int i=1;i<=n;i++)
		{
			str2[i]='.';
		}
		str2[n+1]='\0';
		for(int i=1;i<=n;i++)
		{
			if(str[i]=='G')
			{
				if(g+k>=i)
				{
					continue;
				}
				else
				{
					int j=min(n,i+k);
					while(str2[j]!='.')
					{
						j--;
					}
					str2[j]='G';
					cnt++;
					g=j;
				}
			}
			else
			{
				if(h+k>=i)
				{
					continue;
				}
				else
				{
					int j=min(n,i+k);
					while(str2[j]!='.')
					{
						j--;
					}
					cnt++;
					str2[j]='H';
					h=j;
				}
			}
		}
		printf("%d\n%s\n",cnt,str2+1);
	}
	return 0;
}
